static void modifyValue(int x) {
    x = 100;
}

public static void main(String[] args) {
    int a = 5;
    modifyValue(a);
    System.out.println(a);
}

static void modifyByRef(ref int x) {
    x = 100;
}

static void modifyArray(int[] arr) {
    arr[0] = 100;
}

public static void main(String[] args) {
    int[] nums = {1, 2, 3};
    modifyArray(nums);
    System.out.println(nums[0]);
}

static void reassignArray(int[] arr) {
    arr = new int[]{100, 200};
}

public static void main(String[] args) {
    int[] nums = {1, 2, 3};
    reassignArray(nums);
    System.out.println(nums[0]);
}

static void doubleValue(int x) {
    x = x * 2;
}

public static void main(String[] args) {
    int n = 5;
